function solve_contains_duplicate_within_k(nums, k) {
  const lastSeen = new Map();
  for (let index = 0; index < nums.length; index += 1) {
    const value = nums[index];
    if (lastSeen.has(value) && index - lastSeen.get(value) <= k) {
      return true;
    }
    lastSeen.set(value, index);
  }
  return false;
}

