function solve_max_sum_subarray_k(nums, k) {
  let left = 0;
  let running = 0;
  let best = -Infinity;
  for (let right = 0; right < nums.length; right += 1) {
    running += nums[right];
    if (right - left + 1 > k) {
      running -= nums[left];
      left += 1;
    }
    if (right - left + 1 === k) {
      best = Math.max(best, running);
    }
  }
  return best === -Infinity ? 0 : best;
}

