function solve_permutation_in_string(pattern, text) {
  if (pattern.length > text.length) return false;
  const need = new Map();
  const window = new Map();
  for (const char of pattern) {
    need.set(char, (need.get(char) || 0) + 1);
  }
  let left = 0;
  for (let right = 0; right < text.length; right += 1) {
    window.set(text[right], (window.get(text[right]) || 0) + 1);
    if (right - left + 1 > pattern.length) {
      const nextCount = window.get(text[left]) - 1;
      if (nextCount === 0) window.delete(text[left]);
      else window.set(text[left], nextCount);
      left += 1;
    }
    if (right - left + 1 === pattern.length) {
      let matches = true;
      for (const [char, count] of need.entries()) {
        if ((window.get(char) || 0) !== count) {
          matches = false;
          break;
        }
      }
      if (matches) return true;
    }
  }
  return false;
}

