function solve_minimum_window_substring(source, target) {
  if (!target.length || target.length > source.length) return "";
  const need = new Map();
  for (const char of target) {
    need.set(char, (need.get(char) || 0) + 1);
  }
  const window = new Map();
  let formed = 0;
  let left = 0;
  let best = [Infinity, 0, 0];
  for (let right = 0; right < source.length; right += 1) {
    const char = source[right];
    window.set(char, (window.get(char) || 0) + 1);
    if (need.has(char) && window.get(char) === need.get(char)) {
      formed += 1;
    }
    while (formed === need.size) {
      if (right - left + 1 < best[0]) best = [right - left + 1, left, right];
      const leftChar = source[left];
      window.set(leftChar, window.get(leftChar) - 1);
      if (need.has(leftChar) && window.get(leftChar) < need.get(leftChar)) {
        formed -= 1;
      }
      left += 1;
    }
  }
  return best[0] === Infinity ? "" : source.slice(best[1], best[2] + 1);
}

