function solve_count_nice_subarrays(nums, k) {
  function atMost(limit) {
    let left = 0;
    let oddCount = 0;
    let total = 0;
    for (let right = 0; right < nums.length; right += 1) {
      if (nums[right] % 2 !== 0) oddCount += 1;
      while (oddCount > limit) {
        if (nums[left] % 2 !== 0) oddCount -= 1;
        left += 1;
      }
      total += right - left + 1;
    }
    return total;
  }
  return atMost(k) - atMost(k - 1);
}

