function solve_valid_parentheses(text) {
  const pairs = new Map([[")", "("], ["]", "["], ["}", "{"]]);
  const stack = [];
  for (const char of text) {
    if (pairs.has(char)) {
      if (stack.pop() !== pairs.get(char)) {
        return false;
      }
    } else {
      stack.push(char);
    }
  }
  return stack.length === 0;
}

