class QueueUsingStacks {
  constructor() {
    this.input = [];
    this.output = [];
  }

  push(value) {
    this.input.push(value);
  }

  shiftStacks() {
    if (!this.output.length) {
      while (this.input.length) {
        this.output.push(this.input.pop());
      }
    }
  }

  pop() {
    this.shiftStacks();
    return this.output.pop();
  }

  peek() {
    this.shiftStacks();
    return this.output[this.output.length - 1];
  }
}

