function solve_sliding_window_maximum(nums, k) {
  const deque = [];
  const result = [];
  for (let index = 0; index < nums.length; index += 1) {
    while (deque.length && deque[0] <= index - k) deque.shift();
    while (deque.length && nums[deque[deque.length - 1]] <= nums[index]) deque.pop();
    deque.push(index);
    if (index >= k - 1) result.push(nums[deque[0]]);
  }
  return result;
}

