function solve_simplify_path(pathText) {
  const stack = [];
  for (const segment of pathText.split('/')) {
    if (!segment || segment === '.') continue;
    if (segment === '..') stack.pop();
    else stack.push(segment);
  }
  return '/' + stack.join('/');
}

