function solve_largest_rectangle_histogram(heights) {
  const stack = [];
  let best = 0;
  const extended = [...heights, 0];
  for (let index = 0; index < extended.length; index += 1) {
    while (stack.length && extended[stack[stack.length - 1]] > extended[index]) {
      const height = extended[stack.pop()];
      const left = stack.length ? stack[stack.length - 1] + 1 : 0;
      best = Math.max(best, height * (index - left));
    }
    stack.push(index);
  }
  return best;
}

