function solve_decode_string(text) {
  const countStack = [];
  const stringStack = [];
  let current = '';
  let number = 0;
  for (const char of text) {
    if (char >= '0' && char <= '9') {
      number = number * 10 + Number(char);
    } else if (char === '[') {
      countStack.push(number);
      stringStack.push(current);
      number = 0;
      current = '';
    } else if (char === ']') {
      const repeat = countStack.pop();
      const prefix = stringStack.pop();
      current = prefix + current.repeat(repeat);
    } else {
