function solve_koko_bananas(piles, hours) {
  let left = 1;
  let right = Math.max(...piles);
  let answer = right;
  while (left <= right) {
    const speed = Math.floor((left + right) / 2);
    let needed = 0;
    for (const pile of piles) {
