function solve_rotting_oranges(grid) {
  const rows = grid.length;
  const cols = grid[0].length;
  const queue = [];
  let fresh = 0;
  const directions = [[1,0],[-1,0],[0,1],[0,-1]];

  for (let row = 0; row < rows; row += 1) {
    for (let col = 0; col < cols; col += 1) {
      if (grid[row][col] === 2) queue.push([row, col]);
      if (grid[row][col] === 1) fresh += 1;
    }
  }

  let minutes = 0;
  for (let head = 0; head < queue.length && fresh > 0; ) {
    const levelSize = queue.length - head;
    for (let count = 0; count < levelSize; count += 1) {
      const [row, col] = queue[head];
      head += 1;
      for (const [dr, dc] of directions) {
        const nextRow = row + dr;
        const nextCol = col + dc;
        if (nextRow < 0 || nextRow >= rows || nextCol < 0 || nextCol >= cols) continue;
        if (grid[nextRow][nextCol] !== 1) continue;
        grid[nextRow][nextCol] = 2;
        fresh -= 1;
        queue.push([nextRow, nextCol]);
      }
    }
    minutes += 1;
  }

  return fresh === 0 ? minutes : -1;
}

