function solve_word_ladder(beginWord, endWord, wordList) {
  const words = new Set(wordList);
  if (!words.has(endWord)) return 0;
  const queue = [[beginWord, 1]];

  for (let index = 0; index < queue.length; index += 1) {
    const [word, steps] = queue[index];
    if (word === endWord) return steps;
    for (let position = 0; position < word.length; position += 1) {
      for (let code = 97; code <= 122; code += 1) {
        const nextWord = word.slice(0, position) + String.fromCharCode(code) + word.slice(position + 1);
        if (!words.has(nextWord)) continue;
        words.delete(nextWord);
        queue.push([nextWord, steps + 1]);
      }
    }
  }

  return 0;
}

