function solve_open_lock(deadends, target) {
  const blocked = new Set(deadends);
  if (blocked.has('0000')) return -1;
  const visited = new Set(['0000']);
  const queue = [['0000', 0]];

  function neighbors(state) {
    const result = [];
    for (let index = 0; index < 4; index += 1) {
      const digit = Number(state[index]);
      for (const change of [-1, 1]) {
        const nextDigit = (digit + change + 10) % 10;
        result.push(state.slice(0, index) + nextDigit + state.slice(index + 1));
      }
    }
    return result;
  }

  for (let index = 0; index < queue.length; index += 1) {
    const [state, steps] = queue[index];
    if (state === target) return steps;
    for (const nextState of neighbors(state)) {
      if (blocked.has(nextState) || visited.has(nextState)) continue;
      visited.add(nextState);
      queue.push([nextState, steps + 1]);
    }
  }

  return -1;
}

