function solve_decode_ways(text) {
  if (!text.length || text[0] === '0') return 0;
  const dp = Array(text.length + 1).fill(0);
  dp[0] = 1;
  dp[1] = 1;
  for (let index = 2; index <= text.length; index += 1) {
    const oneDigit = Number(text.slice(index - 1, index));
    const twoDigits = Number(text.slice(index - 2, index));
    if (oneDigit >= 1) dp[index] += dp[index - 1];
    if (twoDigits >= 10 && twoDigits <= 26) dp[index] += dp[index - 2];
  }
  return dp[text.length];
}

