function solve_n_queens(n) {
  const result = [];
  const board = Array.from({ length: n }, () => Array(n).fill('.'));
  const columns = new Set();
  const diagOne = new Set();
  const diagTwo = new Set();

  function backtrack(row) {
    if (row === n) {
      result.push(board.map((line) => line.join('')));
      return;
    }
    for (let col = 0; col < n; col += 1) {
      const d1 = row - col;
      const d2 = row + col;
      if (columns.has(col) || diagOne.has(d1) || diagTwo.has(d2)) continue;
      columns.add(col);
      diagOne.add(d1);
      diagTwo.add(d2);
      board[row][col] = 'Q';
      backtrack(row + 1);
      board[row][col] = '.';
      columns.delete(col);
      diagOne.delete(d1);
      diagTwo.delete(d2);
    }
  }

  backtrack(0);
  return result;
}

