function solve_restore_ip_addresses(text) {
  const result = [];
  const path = [];

  function backtrack(index) {
    if (path.length === 4) {
      if (index === text.length) result.push(path.join('.'));
      return;
    }
    for (let length = 1; length <= 3 && index + length <= text.length; length += 1) {
      const segment = text.slice(index, index + length);
      if ((segment.length > 1 && segment[0] === '0') || Number(segment) > 255) continue;
      path.push(segment);
      backtrack(index + length);
      path.pop();
    }
  }

  backtrack(0);
  return result;
}

